from dataclasses import dataclass
from typing import List


@dataclass
class SprintToilBudget:
    sprint_id: str
    total_engineer_hours: float     # all engineering work this sprint
    toil_hours: float               # sum of ToilEntry.hours_spent across team
    sre_capacity_hours: float       # hours spent on proactive SRE work

    @property
    def toil_pct(self) -> float:
        return (self.toil_hours / self.total_engineer_hours) * 100

    @property
    def is_over_budget(self) -> bool:
        return self.toil_pct > 50.0

    @property
    def budget_status(self) -> str:
        pct = self.toil_pct
        if pct < 35:
            return "healthy"
        elif pct < 50:
            return "warning"        # trending toward limit
        else:
            return "over-budget"    # escalate to engineering manager

    def summary(self) -> str:
        lines = [
            f"Sprint {self.sprint_id} toil budget: {self.toil_pct:.1f}% "
            f"({self.toil_hours:.0f}h / {self.total_engineer_hours:.0f}h)",
            f"Status: {self.budget_status.upper()}",
        ]
        if self.is_over_budget:
            lines.append(
                "ACTION REQUIRED: Toil exceeds 50% — file reduction tickets "
                "and escalate to EM within 48 hours."
            )
        return "\n".join(lines)


def compute_team_toil(entries: List["ToilEntry"],
                      total_capacity: float) -> SprintToilBudget:
    sprint_id = entries[0].sprint if entries else "unknown"
    toil_hours = sum(e.hours_spent for e in entries)
    return SprintToilBudget(
        sprint_id=sprint_id,
        total_engineer_hours=total_capacity,
        toil_hours=toil_hours,
        sre_capacity_hours=total_capacity - toil_hours,
    )

import hashlib
from pathlib import Path
from typing import Optional


class IncrementalIndexer:
    """Replace nightly full-rebuild toil with event-driven incremental updates."""

    def __init__(self, index_client, hash_store: dict[str, str]):
        self.index = index_client
        self.hashes = hash_store   # doc_id -> sha256 of last-indexed content

    def _doc_hash(self, content: str) -> str:
        return hashlib.sha256(content.encode()).hexdigest()

    def upsert_if_changed(self, doc_id: str, content: str,
                          metadata: dict) -> bool:
        """Return True if the document was reindexed; False if skipped."""
        new_hash = self._doc_hash(content)
        if self.hashes.get(doc_id) == new_hash:
            return False          # unchanged; no work done
        embedding = self.index.embed(content)
        self.index.upsert(doc_id, embedding, metadata)
        self.hashes[doc_id] = new_hash
        return True

    def process_batch(self, documents: list[dict]) -> dict:
        updated, skipped = 0, 0
        for doc in documents:
            if self.upsert_if_changed(doc["id"], doc["content"], doc.get("meta", {})):
                updated += 1
            else:
                skipped += 1
        return {"updated": updated, "skipped": skipped}

from dataclasses import dataclass, field
from typing import List


@dataclass
class QuarterlyToilReport:
    quarter: str
    starting_toil_pct: float
    target_toil_pct: float
    ending_toil_pct: float
    completed_tickets: List["ToilReductionTicket"] = field(default_factory=list)

    @property
    def hours_saved_per_sprint(self) -> float:
        return sum(t.estimated_hours_saved_per_sprint for t in self.completed_tickets
                   if t.status.value == "done")

    @property
    def target_met(self) -> bool:
        return self.ending_toil_pct <= self.target_toil_pct

    def format_summary(self) -> str:
        status = "MET" if self.target_met else "MISSED"
        lines = [
            f"Q{self.quarter} Toil Reduction Report",
            f"  Start: {self.starting_toil_pct:.1f}%  "
            f"Target: {self.target_toil_pct:.1f}%  "
            f"Actual: {self.ending_toil_pct:.1f}%  [{status}]",
            f"  Automations shipped: {len(self.completed_tickets)}",
            f"  Hours saved/sprint: {self.hours_saved_per_sprint:.1f}h",
        ]
        for ticket in self.completed_tickets:
            lines.append(f"  ✓ {ticket.ticket_line()}")
        return "\n".join(lines)
